import React, { useState, useEffect } from 'react';
import { Container, Paper, Typography, TextField, Button, Box, Autocomplete } from '@mui/material';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

export default function NewQuestion({ showSnackbar }) {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [tags, setTags] = useState([]);
  const [allTags, setAllTags] = useState([]);
  const [showAllTags, setShowAllTags] = useState(false);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    // Lấy danh sách câu hỏi để tổng hợp tag
    axios.get('http://localhost:8080/api/questions')
      .then(res => {
        const tags = Array.from(new Set(res.data.flatMap(q => q.tags || [])));
        setAllTags(tags);
      })
      .catch(() => setAllTags([]));
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!tags.length || tags.filter(t => t !== '__SEE_MORE__').length === 0) {
      showSnackbar && showSnackbar('Vui lòng chọn ít nhất 1 tag!', 'error');
      return;
    }
    setLoading(true);
    // Loại bỏ '__SEE_MORE__' nếu có và chuyển tags thành chuỗi
    const cleanTags = tags.filter(t => t !== '__SEE_MORE__');
    const tagsString = cleanTags.join(', ');
    console.log('DEBUG tags gửi backend:', tagsString);
    try {
      await axios.post('http://localhost:8080/api/questions', { title, content, tags: tagsString });
      showSnackbar && showSnackbar('Đã thêm câu hỏi mới!', 'success');
      navigate('/questions');
    } catch (err) {
      showSnackbar && showSnackbar('Thêm câu hỏi thất bại!', 'error');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm" sx={{mt:6}}>
      <Paper elevation={3} sx={{p:4}}>
        <Typography variant="h5" gutterBottom>Thêm câu hỏi mới</Typography>
        <Box component="form" onSubmit={handleSubmit} sx={{display:'flex', flexDirection:'column', gap:2}}>
          <TextField label="Tiêu đề" value={title} onChange={e => setTitle(e.target.value)} required fullWidth />
          <TextField label="Nội dung" value={content} onChange={e => setContent(e.target.value)} required fullWidth multiline minRows={4} />
          <Autocomplete
            multiple
            freeSolo
            options={showAllTags ? allTags : allTags.slice(0,7).concat(allTags.length > 7 ? ['__SEE_MORE__'] : [])}
            value={tags}
            onChange={(e, value) => {
              if (value.includes('__SEE_MORE__')) {
                setShowAllTags(true);
                setTags(tags);
              } else {
                setTags(value);
              }
            }}
            renderOption={(props, option) =>
              option === '__SEE_MORE__' ? (
                <li {...props} style={{fontStyle:'italic', color:'#1976d2', fontWeight:600}}>
                  ... Xem thêm tag
                </li>
              ) : (
                <li {...props}>{option}</li>
              )
            }
            renderInput={(params) => <TextField {...params} label="Chọn hoặc nhập tag" />}
            sx={{background:'#fff'}}
          />
          <Button type="submit" variant="contained" color="primary" disabled={loading}>
            {loading ? 'Đang gửi...' : 'Thêm câu hỏi'}
          </Button>
        </Box>
      </Paper>
    </Container>
  );
}
